class SndEng {
  constructor() { this.ctx = null; this.on = true; }
  _init() { if (!this.ctx) try { this.ctx = new (window.AudioContext || window.webkitAudioContext)(); } catch(e) {} }
  play(t) {
    if (!this.on) return; this._init(); if (!this.ctx) return;
    const m = {
      ok:    [[523,.07],[659,.07],[784,.08],[1047,.22]],
      ko:    [[330,.1],[220,.22]],
      tick:  [[1600,.04]],
      win:   [[523,.06],[659,.06],[784,.06],[1047,.07],[1319,.38]],
      badge: [[784,.06],[1047,.06],[1319,.07],[1568,.42]],
      start: [[392,.12],[523,.12],[659,.14]],
    };
    let ts = this.ctx.currentTime;
    (m[t] || []).forEach(([freq, dur]) => {
      const o = this.ctx.createOscillator(), g = this.ctx.createGain();
      o.connect(g); g.connect(this.ctx.destination);
      o.type = t === "ko" ? "sawtooth" : "sine"; o.frequency.value = freq;
      g.gain.setValueAtTime(.22, ts); g.gain.exponentialRampToValueAtTime(.001, ts + dur);
      o.start(ts); o.stop(ts + dur + .01); ts += dur;
    });
  }
}
const SND = new SndEng();

